INSERT INTO `sys_email` VALUES (1,'X_EMAIL_ACCOUNT_CREATION','Creación de Cuenta de Usuario','Email de envío de acceso como nuevo usuario del sistema.','soporte@empleos.click','El equipo de Empleos.Click',NULL,'yecid.pra@gmail.com;yecid_pra@hotmail.com','Creación de su Cuenta de Usuario','<span style=\"font-family: Arial;\">Hola ~NOMBRE~, te informamos que tu cuenta en el sistema fue creada exitosamente.<br><br>Para acceder debes ingresar al siguiente enlace:<br><br></span><span style=\"font-family: Arial;\"><a target=\"_blank\" href=\"~ACCESS_LINK~\"><span style=\"font-family: Arial;\">~ACCESS_LINK~</span></a><br><br>Tienes un password temporal que deberás cambiar al acceder al sistema, este password es: ~PASSWORD~ <br><br>Agradecemos tu confianza y esperamos brindarte una experiencia agradable.<br><br>Saludos<br><span style=\"font-style: italic;\"><br>El equipo de <a href=\"http://www.empleos.click\">Empleos.Click</a><br></span></span>',NULL,'generic',0,'2016-03-08 06:19:49','0000-00-00 00:00:00'),(2,'X_EMAIL_PASSWORD_REQUEST','Recuperación de Acceso','Es el correo de recuperación de accesos al sistema','soporte@empleos.click','Soporte Empleos.Click',NULL,'yecid.pra@gmail.com;yecid_pra@hotmail.com','Recuperación de contraseña solicitada','<span style=\"font-family: Arial;\">Hola ~NOMBRE~, hemos recibido una solicitud de recuperación de contraseña en nuestro sistema.<br><br>Por favor accede al siguiente enlace para recuperar tu acceso al sistema:<br><br></span><span style=\"font-family: Arial;\"><a target=\"_blank\" href=\"~RESET_LINK~\"><span style=\"font-family: Arial;\">~RESET_LINK~</span></a><br><br>Saludos<br><span style=\"font-style: italic;\"><br>El equipo de <a href=\"http://www.empleos.click\" target=\"_blank\">Empleos.Click</a></span></span><br>',NULL,'generic',0,'2016-03-09 00:57:39','0000-00-00 00:00:00'),(3,'J_EMAIL_SUBSCRIPTION_INITIAL','Suscripción de Usuario','Correo de bienvenida al portal de empleos.\r\n\r\nEl Equipo de Empleos.Click','soporte@empleos.click','El equipo de Empleos.Click',NULL,'empleos.click@gmail.com; yecid.pra@gmail.com; raul.ehb@gmail.com; gustavo.flores.alconini@gmail.com','Bienvenida a Empleos.Click','Hola ~NOMBRE_SIMPLE~,<br><br>Gracias por suscribirte en <a href=\"https://www.empleos.click\" target=\"_blank\">Empleos.Click</a> , el portal de empleos mas moderno y preferido.<br><br>Te estaremos enviando periódicamente información con los requerimientos que vayan apareciendo relacionados a <span style=\"font-weight: bold;\">~FORMACION~</span>.<br><br>Muy pronto estaremos con más sorpresas y oportunidades mejoradas de trabajo.<br><br>Gracias por tu confianza y preferencia.<br><br>Saludos<br><br>El equipo de Empleos.Click<br><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br><table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\"><div><span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.comT/empleos.clic\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n<div><span style=\"color:#bcbec0\">Recibiste este correo por una solicitud realizada hace poco.</span></div>\r\n<div> </div>\r\n</div>\r\n</div>',NULL,'generic',0,'2016-04-10 00:19:16','0000-00-00 00:00:00'),(4,'J_EMAIL_NOTIFICATION_SUBSCRIBE','Notificaciön a Suscriptor','Correo de requerimientos de personal como Notificaciön a Suscriptor. El Equipo de Empleos.Click','info@empleos.click','El equipo de Empleos.Click',NULL,'empleos.click@gmail.com;','Requerimientos de Personal','Hola ~NOMBRE~,<br><br>En <a href=\"https://www.empleos.click\" target=\"_blank\">Empleos.Click</a> estamos ayudando a muchas personas a encontrar nuevos trabajos y deseamos ayudarte a ti también.<br><br>Por eso te informamos sobre las nuevas oportunidades laborales que podrían resultarte de interés. ~FRASE_DETALLE~:<br><br>~DETALLE_AVISOS~<br><br><br>Puedes revisar estos y muchos mas requerimientos de personal vigentes en tu portal  <a href=\"https://www.empleos.click\" target=\"_blank\">www.Empleos.Click</a> .<br><br><br>Gracias nuevamente.<br><br>Saludos<br><br>El equipo de Empleos.Click<br><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br><table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\"><div><span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.comT/empleos.click\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n<div><span style=\"color:#bcbec0\">Recibiste este correo por una solicitud realizada hace poco.</span></div>\r\n<div> </div>\r\n</div>\r\n</div>',NULL,'generic',0,'2017-11-22 03:15:38','0000-00-00 00:00:00'),(5,'J_EMAIL_ENTITY_SUBSCRIPTION','Suscripción de Entidad','Correo de bienvenida al portal de empleos. El Equipo de Empleos.Click','soporte@empleos.click','El equipo de Empleos.Click',NULL,'empleos.click@gmail.com','Tu Suscripción en Empleos.Click','Hola,<br><br>En <a href=\"https://www.empleos.click\" target=\"_blank\">Empleos.Click</a> se ha iniciado el registro de la empresa/negocio <span style=\"font-weight: bold;\">~NOMBRE_SIMPLE~</span> , para completar el registro ingresa en el siguiente enlace:<br><br> <div style=\"text-align: center;\"><a href=\"~LINK_CONFIRMACION~\" target=\"_blank\">~LINK_CONFIRMACION~</a><br></div><br>Una vez que completes este registro podrás publicar los requerimientos de personal completamente gratis en nuestra plataforma y gozar de los beneficios de anunciar en el portal de empleos de mayor crecimiento del país.<span style=\"font-weight: bold;\"><br></span><br>Gracias por la confianza depositada, estamos siempre a tu servicio.<br><br>Saludos cordiales.<br><br>El equipo de<span style=\"color: inherit;\"> <span style=\"font-weight: bold;\">Empleos.Click</span></span><span style=\"font-weight: bold;\"><br></span>La Paz - Bolivia<br><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br>\r\n<table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\">\r\n<span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.comT/empleos.click\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n<div><span style=\"color:#bcbec0\">Recibiste este correo por una solicitud realizada hace poco.</span></div>\r\n</div>\r\n<br>\r\n<h5 style=\"text-align:center;\"><span style=\"color: rgb(231, 99, 99);\"><span style=\"font-weight: normal;\">Si tu empresa/negocio no solicitó esta suscripción solamente solamente debes ignorar este correo.</span></span><br></h5>',NULL,'generic',0,'2017-12-28 04:36:46',NULL),(6,'J_EMAIL_NOTIFICATION_DISELO','Díselo a un amigo','Email de difusión de oferta de empleo a un amigo','info@empleos.click','El equipo de Empleos.Click',NULL,'empleos.click@gmail.com; yecid.pra@gmail.com; raul.ehb@gmail.com; gustavo.flores.alconini@gmail.com','~REMITENTE~ te envía una oferta de empleo','Hola ~NOMBRE~, tu amigo ~REMITENTE~ te quiere avisar que existe una oferta de trabajo que puede ser de tu interés:<br><div style=\"text-align: center;\"><span style=\"font-weight: bold;\">~CARGO~</span><br>(~NOMBRE_EMPRESA~)</div><div style=\"text-align: center;\"><br></div><div>Para ver los detalles de la oferta ingresa en el portal de empleos:</div><div style=\"text-align: center;\"> <a href=\"~LINK_AVISO~\" target=\"_blank\">Empleos.Click  >  ~CARGO~<br></a></div><div><br></div>Encuentra esta y muchas más ofertas laborales serias cada semana en el portal de empleos mas confiable y seguro de Bolivia<span style=\"color: rgb(66, 139, 202);\"> </span><a href=\"https://www.empleos.click\" target=\"_blank\">www.Empleos.Click</a> .<br><br>Saludos<br><br>El equipo de Empleos.Click<br><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br><table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\"><div><span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.com/empleos.click\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n<div><span style=\"color:#bcbec0\">Recibiste este correo por una solicitud realizada hace poco.</span></div>\r\n<div> </div>\r\n</div>\r\n</div>',NULL,'generic',0,'2018-07-16 03:50:49',NULL),(7,'D_EMAIL_INVITATION_DIRECTORIO','Invitacion a Empresas del DirectorioDB','Publique Gratis sus Requerimientos de Personal','erwin.chocala@empleos.click','Erwin Chocala',NULL,'empleos.click@gmail.com','Publique Gratis sus Requerimientos de Personal en Empleos.Click','Buenos días:<br><br><div>Señores <span style=\"font-weight: bold;\">~NOMBRE_EMPRESA~</span> , les escribo de parte de <a href=\"https://www.empleos.click/index.htm\" target=\"_blank\">Empleos.Click</a>.</div><div><br></div><div>Somos el portal boliviano de mayor crecimiento y nos gustaría ayudarles en la difusión de su requerimiento por medio de nuestro portal de empleos; como dato, a través de los nuestros medios de difusión y los <span style=\"font-weight: bold;\">13000 fans</span> que tenemos en facebook, cada mes<span style=\"font-weight: bold;\"> más de 20000 bolivianos buscan empleo en nuestro portal</span>.<br></div><div><div><br></div></div><div>La suscripción de su empresa es <span style=\"font-weight: bold;\">completamente gratuita y online</span>, sin compromisos de permanencia u otras obligaciones. Para suscribirse solo debe ingresar a el siguiente enlace:<br> </div><br><div style=\"text-align: center;\"><a href=\"~LINK_INTERNO~\" target=\"_blank\">~LINK_AVISO~</a><br></div><br><div>Y en unos simples pasos estará suscrito en <a href=\"https://www.empleos.click/index.htm\" target=\"_blank\">Empleos.Click</a> ampliando el alcance de sus requerimientos en un canal serio que le dará alcance a los mejores talentos.</div><div><br></div><div>Le invitamos a unirse a nuestro portal, donde permitimos a las empresas conectar con aspirantes con ímpetú de demostrar lo \r\nmejor de su talento.</div><div><br></div>Gracias por la atención prestada, estamos a tu servicio.<br><br>Saludos cordiales.<br><div><br></div><div>Erwin Chocala A.<br>\r\n<i>Agente de Comunicaciones</i><br>\r\n<b>Empleos.Click<font size=\"-2\"><br>\r\n</font></b>\r\n<font style=\"line-height: 1\" size=\"-2\"> Of.: Achumani,\r\n                        calle 29 #1851<br>\r\n                        Cel.: </font><font size=\"-2\"><font size=\"-2\">76258662 - 74263040 </font><br>\r\n                        La Paz - Bolivia \r\n<br></font>\r\n</div><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br>\r\n<table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\">\r\n<span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.comT/empleos.click\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n\r\n</div>',NULL,'generic',0,'2018-09-06 06:49:21',NULL);
